// ToolDescriptor is the exact function metadata exposed to the main ChatModel.
// InputSchema is generated by Eino from the same Go input type used at runtime,
// so the administrator view cannot drift from the schema seen by the model.
type ToolDescriptor struct {
	Name        string          `json:"name"`
	Description string          `json:"description"`
	Category    string          `json:"category"`
	Guard       string          `json:"guard"`
	Enabled     bool            `json:"enabled"`
	InputSchema json.RawMessage `json:"input_schema"`
}

type ToolCatalog struct {
	Loaded        bool             `json:"loaded"`
	Agent         string           `json:"agent"`
	Framework     string           `json:"framework"`
	ExecutionMode string           `json:"execution_mode"`
	ProviderID    string           `json:"provider_id,omitempty"`
	Model         string           `json:"model,omitempty"`
	LoadedAt      string           `json:"loaded_at,omitempty"`
	Count         int              `json:"count"`
	Total         int              `json:"total"`
	Tools         []ToolDescriptor `json:"tools"`
}

// DescribeTools reads Eino's resolved ToolInfo rather than maintaining a
// second hand-written function schema for the Web control plane.
func DescribeTools(ctx context.Context, tools []tool.BaseTool) ([]ToolDescriptor, error) {
	descriptors := make([]ToolDescriptor, 0, len(tools))
	for _, candidate := range tools {
		info, err := candidate.Info(ctx)
		if err != nil {
			return nil, err
		}
		schemaJSON := json.RawMessage(`{"type":"object","properties":{}}`)
		if info.ParamsOneOf != nil {
			inputSchema, err := info.ParamsOneOf.ToJSONSchema()
			if err != nil {
				return nil, err
			}
			if inputSchema != nil {
				schemaJSON, err = json.Marshal(inputSchema)
				if err != nil {
					return nil, err
				}
			}
		}
		descriptors = append(descriptors, ToolDescriptor{
			Name: info.Name, Description: info.Desc, Category: toolCategory(info.Name), Guard: toolGuard(info.Name), Enabled: true, InputSchema: schemaJSON,
		})
	}
	return descriptors, nil
}

func toolCategory(name string) string {
	switch {
	case strings.HasPrefix(name, "ops_plan_"):
		return "planning"
	case strings.HasPrefix(name, "ops_skill_"):
		return "skills"
	case strings.HasPrefix(name, "mcp__"):
		return "mcp"
	case strings.HasPrefix(name, "workspace_"):
		return "workspace"
	case name == "web_search":
		return "web"
	case strings.HasPrefix(name, "ssh_host_"):
		return "hosts"
	case strings.HasPrefix(name, "ssh_task_"):
		return "tasks"
	case strings.HasPrefix(name, "ssh_file_") || strings.HasPrefix(name, "ssh_config_"):
		return "remote_files"
	case strings.HasPrefix(name, "ssh_history_"):
		return "history"
	default:
		return "execution"
	}
}

func toolGuard(name string) string {
	switch name {
	case "ops_plan_create", "ops_plan_step_update":
		return "agent_state"
	case "ssh_exec", "ssh_run_script", "ssh_task_start", "ssh_file_read", "ssh_file_search":
		return "policy_checked"
	case "ssh_file_write", "ssh_file_apply_patch", "ssh_config_apply", "ssh_config_restore", "workspace_file_apply_patch", "workspace_file_upload", "workspace_shell":
		return "approval_required"
	case "ssh_task_cancel":
		return "audited_control"
	default:
		if strings.HasPrefix(name, "mcp__") {
			return "external_mcp"
		}
		return "read_only"
	}
}

