const rejectedOperationNextAction = "stop this operation, do not resubmit it, and follow operator_instruction as the human's authoritative replacement instruction"

func normalizeToolStatus(meta *domain.ToolMeta, status string) {
	meta.ToolVersion = "1.1"
	meta.Code = status
	switch status {
	case "completed", "running":
		meta.OK = true
	case "approval_required":
		meta.OK = true
		meta.NextAction = "wait for the human decision; do not resubmit or try to approve this operation"
	case "rejected":
		meta.Message = "the human operator rejected this operation"
		meta.NextAction = rejectedOperationNextAction
	case "failed":
		meta.Message = "the operation failed; inspect stderr in this Tool result"
		meta.Retryable = true
		meta.NextAction = "use the returned stderr as evidence, correct the cause, and do not repeat unchanged input"
	case "denied":
		meta.Message = "the operation was denied by policy"
		meta.NextAction = "respect the policy decision and choose a safer operation"
	case "expired":
		meta.Message = "the human approval expired"
		meta.NextAction = "reassess whether the operation is still needed before proposing it again"
	case "cancelled", "interrupted":
		meta.Message = "the task did not complete"
		meta.NextAction = "inspect the task result and current state before deciding whether further work is needed"
	}
}

func NormalizeExecToolResult(result domain.ExecResult, err error) (domain.ExecResult, error) {
	if err == nil {
		normalizeToolStatus(&result.ToolMeta, result.Status)
		return result, nil
	}
	result.ToolVersion = "1.1"
	if errors.Is(err, context.Canceled) {
		return result, err
	}
	result.OK = false
	result.Message = err.Error()
	result.Code, result.Retryable, result.NextAction = classifyToolError(err)
	if result.Status == "" {
		result.Status = "failed"
	}
	return result, nil
}

func TaskToolOutput(task domain.Task, result domain.ExecResult, taskErr string, err error) (TaskOutput, error) {
	output := TaskOutput{Task: task, Result: result, OperatorInstruction: result.OperatorInstruction, Error: taskErr}
	if err == nil {
		normalizeToolStatus(&output.ToolMeta, task.Status)
		return output, nil
	}
	output.ToolVersion = "1.1"
	if errors.Is(err, context.Canceled) {
		return output, err
	}
	output.OK = false
	output.Message = err.Error()
	output.Code, output.Retryable, output.NextAction = classifyToolError(err)
	return output, nil
}

func TaskStartToolOutput(svc *service.Service, task domain.Task, startErr error) (TaskOutput, error) {
	if task.ID == "" {
		return TaskToolOutput(task, domain.ExecResult{}, "", startErr)
	}
	storedTask, result, taskErr, getErr := svc.GetTask(task.ID)
	if getErr == nil {
		task = storedTask
	} else if startErr == nil {
		startErr = getErr
	}
	return TaskToolOutput(task, result, taskErr, startErr)
}

func classifyToolError(err error) (string, bool, string) {
	message := strings.ToLower(err.Error())
	switch {
	case errors.Is(err, store.ErrNotFound):
		return "not_found", false, "verify the identifier or list available resources; do not retry the same missing identifier"
	case errors.Is(err, context.DeadlineExceeded), strings.Contains(message, "timed out"), strings.Contains(message, "timeout"):
		return "timeout", true, "narrow the operation or use ssh_task_start for a long-running command"
	case strings.Contains(message, "denied"), strings.Contains(message, "forbidden"):
		return "denied", false, "respect the policy decision and choose a safer operation"
	case strings.Contains(message, "required"), strings.Contains(message, "invalid"), strings.Contains(message, "unsupported"):
		return "validation_failed", false, "correct the tool input using the error message; do not repeat unchanged input"
	case strings.Contains(message, "changed"), strings.Contains(message, "conflict"):
		return "conflict", true, "read the current state again before proposing another change"
	default:
		return "remote_failed", true, "inspect stderr and gather narrower read-only evidence before retrying"
	}
}

func NormalizeWebSearchToolResult(result domain.WebSearchResponse, err error) (domain.WebSearchResponse, error) {
	result.ToolVersion = "1.0"
	result.ContentIsUntrusted = true
	if err == nil {
		result.OK = true
		result.Code = "completed"
		return result, nil
	}
	if errors.Is(err, context.Canceled) {
		return result, err
	}
	result.OK = false
	result.Message = err.Error()
	switch {
	case errors.Is(err, service.ErrWebSearchDisabled):
		result.Code = "configuration_required"
		result.NextAction = "tell the operator that Web Search must be enabled and configured in Settings; do not retry"
	case errors.Is(err, context.DeadlineExceeded), strings.Contains(strings.ToLower(err.Error()), "timeout"):
		result.Code = "timeout"
		result.Retryable = true
		result.NextAction = "retry once with a narrower query or fewer results"
	case errors.Is(err, service.ErrWebSearchUpstream):
		result.Code = "provider_failed"
		result.Retryable = true
		result.NextAction = "inspect the provider error and retry once only when it appears transient"
	default:
		result.Code, result.Retryable, result.NextAction = classifyToolError(err)
	}
	return result, nil
}

